sql.if:
SELECT /*+ INDEX(REQ MCP_REQUEST_IDX4 PK_MCP_REQUEST MCP_REQUEST_IDX3 MCP_REQUEST_IDX9) USE_NL(REQ CST SAL MOV DLV) */ ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'CMN0032' AND X.CD_VAL = REQ.SERVICE_TYPE ) AS SERVICE_NAME , REQ.RES_NO , CST.CSTMR_NAME , TRIM(CST.CSTMR_FOREIGNER_RRN) AS CSTMR_FOREIGNER_RRN , TRIM(CST.CSTMR_NATIVE_RRN) AS CSTMR_NATIVE_RRN /* 주민번호 */ , REQ.CSTMR_TYPE , DECODE(REQ.CSTMR_TYPE, 'FN', TRIM(CST.CSTMR_FOREIGNER_RRN), TRIM(CST.CSTMR_NATIVE_RRN)) AS SSN , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP9004' AND X.CD_VAL = REQ.REQ_BUY_TYPE ) AS REQ_BUY_TYPE , ( SELECT X.DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP X WHERE CD_GROUP_ID = 'NSC' AND X.DTL_CD = MOV.MOVE_COMPANY ) AS MOVE_COMPANY , ( SELECT PRDT_NM || '(' || PRDT_CODE || ')' FROM CMN_INTM_MDL WHERE PRDT_ID = SAL.MODEL_ID ) AS PRDT_NM , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'CMN0044' AND X.USG_YN = 'Y' AND X.CD_VAL = REQ.REQ_MODEL_COLOR ) AS PRDT_COLR_NM , DECODE(TRIM(CST.CSTMR_MOBILE_FN) || TRIM(CST.CSTMR_MOBILE_MN) || TRIM(CST.CSTMR_MOBILE_RN), '', TRIM(CST.CSTMR_TEL_FN) || '-' || TRIM(CST.CSTMR_TEL_MN) || '-' || TRIM(CST.CSTMR_TEL_RN), TRIM(CST.CSTMR_MOBILE_FN) || '-' || TRIM(CST.CSTMR_MOBILE_MN) || '-' || TRIM(CST.CSTMR_MOBILE_RN) ) AS CSTMR_MOBILE , ( SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = REQ.CNTPNT_SHOP_ID ) || '/' || REQ.CNTPNT_SHOP_ID AS AGENT_NAME /* 대리점 */ , ( SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = SAL.SOC_CODE AND SERVICE_TYPE = 'P' AND ROWNUM = 1 ) || '(' || SAL.SOC_CODE || ')' AS SOC_NAME /* 요금제 */ , DECODE(SUBSTR(REQ.DIS_PRMT_ID,1,1),'F',(SELECT '(오프라인) ' || PRMT_NM FROM MSP_DIS_MST WHERE PRMT_ID = REQ.DIS_PRMT_ID), 'C',(SELECT '(온라인) ' || PRMT_NM FROM MSP_CHRG_PRMT WHERE PRMT_ID = REQ.DIS_PRMT_ID), '','') AS DIS_PRMT_NM , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP9001' AND X.CD_VAL = REQ.OPER_TYPE ) AS OPER_NAME /* 업무구분 */ , TO_CHAR(REQ.REQ_IN_DAY, 'YYYY-MM-DD') AS REQ_IN_DAY /* 신청일자 */ , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP0005' AND X.CD_VAL = REQ.PSTATE) AS PSTATE_NAME /* 신청서상태 */ , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP0006' AND X.CD_VAL = REQ.REQUEST_STATE_CODE) AS REQUEST_STATE_NAME /* 진행상태*/ , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP0007' AND X.CD_VAL = NVL(REQ.ON_OFF_TYPE, '0')) AS ON_OFF_NAME /* 온/오프라인 */ , REQ.ON_OFF_TYPE , REQ.OPEN_MARKET_REFERER /* 유입경로 */ , NVL(REQ.REC_YN, 'N') AS REC_YN /* 녹취여부 */ , NVL(REQ.SHOP_NM, FN_GET_ORGNM(REQ.SHOP_CD)) || '/' || REQ.SHOP_CD AS SHOP_NM /* 판매점 */ , REQ.SHOP_USM_ID AS USR_ID /* 판매자ID */ , ( SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = REQ.SHOP_USM_ID ) AS USR_NM /* 판매자 */ , REQ.REQUEST_KEY , CST.CSTMR_ADDR || ' ' || CST.CSTMR_ADDR_DTL AS CSTMR_ADDR , DLV.DLVRY_ADDR || ' ' || DLV.DLVRY_ADDR_DTL AS DLVRY_ADDR , SUBSTR(DLV.DLVRY_POST,1,3) || '-' || SUBSTR(DLV.DLVRY_POST,4,3) AS DLVRY_POST , TRIM(DLV.DLVRY_MOBILE_FN) || '-' || TRIM(DLV.DLVRY_MOBILE_MN) || '-' || TRIM(DLV.DLVRY_MOBILE_RN) AS DLVRY_MOBILE , TRIM(CST.CSTMR_TEL_FN) || '-' || TRIM(CST.CSTMR_TEL_MN) || '-' || TRIM(CST.CSTMR_TEL_RN) AS CSTMR_TEL_NO , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'CMN0058' AND X.CD_VAL = SAL.SPRT_TP ) AS SPRT_TP_NM , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP9011' AND X.CD_VAL = CST.RECOMMEND_FLAG_CD) AS RECOMMEND_FLAG_NM /* 추천인구분명 */ , CST.RECOMMEND_INFO AS RECOMMEND_INFO /* 추천인정보 */ , NVL(REQ.PROD_TYPE, '01') AS PROD_TYPE , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP0063' AND X.CD_VAL = NVL(REQ.PROD_TYPE, '01')) AS PROD_TYPE_NM , REQ.CLAUSE_RENTAL_MODEL_CP , REQ.CLAUSE_RENTAL_MODEL_CP_PR , REQ.CLAUSE_RENTAL_SERVICE , SAL.RENTAL_BASE_AMT , SAL.RENTAL_BASE_DC_AMT , SAL.RENTAL_MODEL_CP_AMT , DECODE(REQ.RVISN_ID, 'ACEN', REQ.RVISN_ID, FN_GET_USRNM(REQ.RVISN_ID)) AS RVISN_NM /*수정자*/ , TO_CHAR(REQ.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM /* 2018-05-09, 직접개통 처리여부 추가 */ ,( SELECT COUNT(1) FROM CMN_GRP_CD_MST A WHERE A.GRP_ID = 'RCP0073' AND A.USG_YN = 'Y' AND A.CD_VAL = REQ.CNTPNT_SHOP_ID AND EXISTS (SELECT 1 FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP0074' AND CD_VAL = REQ.OPER_TYPE AND USG_YN = 'Y') AND EXISTS (SELECT 1 FROM CMN_USR_MST WHERE USR_ID = #{sessionUserId} AND KOS_ID IS NOT NULL) ) AS OSST_CHK , REQ.SCAN_ID /* 2024-03-26 KNOTE 적용대리점 확인 */
/* 속도 개선 테스트를 위한 주석처리*/ /*, ( SELECT COUNT(1) FROM ORG_ORGN_INFO_MST A , MDS_ORG_CPNT_INFO B WHERE A.ORGN_ID = B.CPNT_ID AND A.HGHR_ORGN_CD = REQ.CNTPNT_SHOP_ID AND B.FILE_NM = (SELECT MAX(FILE_NM) FROM MDS_ORG_CPNT_INFO) AND B.SALE_TYPE_DIV_CD IN (SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0075' AND USG_YN = 'Y') ) AS KNOTE_CHK*/ FROM MCP_REQUEST@DL_MCP REQ , MCP_REQUEST_CSTMR@DL_MCP CST , MCP_REQUEST_SALEINFO@DL_MCP SAL , MCP_REQUEST_MOVE@DL_MCP MOV , MCP_REQUEST_DLVRY@DL_MCP DLV WHERE REQ.REQUEST_KEY = CST.REQUEST_KEY AND REQ.REQUEST_KEY = SAL.REQUEST_KEY AND REQ.REQUEST_KEY = MOV.REQUEST_KEY AND REQ.REQUEST_KEY = DLV.REQUEST_KEY
AND REQ.REQ_IN_DAY BETWEEN TO_DATE(#{searchStartDt},'YYYYMMDD') AND TO_DATE(#{searchEndDt},'YYYYMMDD') + 1 /*신청일자*/
AND REQ.SERVICE_TYPE = #{pServiceType} /*서비스타입-선후불*/
AND REQ.OPER_TYPE = #{pOperType} /*신청유형-신규가입/번호이동정보/기기변경정보*/
AND REQ.CNTPNT_SHOP_ID = #{cntpntShopId}
AND REQ.SHOP_CD = #{pAgentCode}
AND (REQ.SHOP_CD = #{pAgentCode} OR REQ.CNTPNT_SHOP_ID = #{pAgentCode})
AND REQ.SHOP_CD = #{pAgentCode}
AND REQ.REQUEST_STATE_CODE = #{pRequestStateCode} /*접수상태코드-진행상태*/
AND CST.CSTMR_NAME LIKE #{pSearchName} || '%' /*검색구분-고객명(pSearchGbn=1로 구분)*/
AND REQ.CONTRACT_NUM = #{pSearchName} /*검색구분-예약번호(pSearchGbn=2로 구분)*/
AND (CST.CSTMR_MOBILE_FN || CST.CSTMR_MOBILE_MN || CST.CSTMR_MOBILE_RN = TRANSLATE(#{pSearchName},'1234567890-','1234567890') OR CST.CSTMR_TEL_FN || CST.CSTMR_TEL_MN || CST.CSTMR_TEL_RN = TRANSLATE(#{pSearchName},'1234567890-','1234567890')) /*검색구분-연락처(searchGbn=3로 구분)*/
AND REQ.REQ_PHONE_SN = #{pSearchName}
AND REQ.RES_NO = #{pSearchName}
AND SAL.SOC_CODE IN ( SELECT RATE_CD FROM MSP_RATE_MST WHERE SERVICE_TYPE = 'P' AND RATE_NM LIKE UPPER(#{pSearchName}) || '%' )
AND REQ.PSTATE = #{pPstate}
AND REQ.REQ_BUY_TYPE = #{reqBuyType}
AND SAL.SPRT_TP = #{sprtTp}
AND NVL(REQ.PROD_TYPE, '01') = #{prodType}
AND REQ.ON_OFF_TYPE = #{onOffType}
AND REQ.INSR_PROD_CD = #{insrProdCd}
AND REQ.USIM_KINDS_CD = '09'
AND EXISTS (SELECT 1 FROM NMCP_ACEN_REQ@DL_MCP WHERE REQUEST_KEY = REQ.REQUEST_KEY)
AND REQ.ON_OFF_TYPE NOT IN ('5','7')
AND SUBSTR(DECODE(REQ.CSTMR_TYPE, 'FN', CRYPTO_AES256.DEC_AES(TRIM(CST.CSTMR_FOREIGNER_RRN)), CRYPTO_AES256.DEC_AES(TRIM(CST.CSTMR_NATIVE_RRN))), 0, 6) = #{pBirthDayVal}
ORDER BY REQ.REQUEST_KEY DESC

mapper.select:
/* RcpNewMgmtMapper.checkNewPhoneSN */ SELECT B.RPRS_PRDT_ID AS prdtId , A.PRDT_SRL_NUM AS prdtSrlNum , CASE WHEN SVC_CT_NUM IS NULL OR A.SVC_CT_NUM = '000000000' THEN 0 ELSE 1 END svcCtNum , FN_GET_RPRSPRDTCD(B.PRDT_ID) AS prdtCode , B.PRDT_COLR_CD AS prdtColrCd , B.MNFCT_ID AS mnfctId , A.ORGN_ID AS orgnId , FN_GET_ORGNM(A.ORGN_ID) AS orgnNm FROM LGS_PRDT_SRL_MST A , CMN_INTM_MDL B WHERE 1 = 1
AND TO_CHAR(SYSDATE, 'YYYYMMDD')
AND REPLACE(#{reqInDay}, '-', '')
BETWEEN NVL(B.PRDT_LNCH_DT,
TO_CHAR(SYSDATE, 'YYYYMMDD')
REPLACE(#{reqInDay}, '-', '')
) AND B.PRDT_DT
AND A.PRDT_SRL_NUM = #{reqPhoneSn}
AND A.RPRS_PRDT_ID = #{prdtId}
AND A.ORGN_ID = #{cntpntShopId}
AND A.LOGIS_PROC_STAT_CD IN ( SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'LGS1000' AND ETC3 = 'AG' AND ETC5 = 'Z11' ) AND A.PRDT_ID = B.PRDT_ID UNION ALL SELECT B.RPRS_PRDT_ID AS prdtId , A.PRDT_SRL_NUM AS prdtSrlNum , CASE WHEN A.SVC_CT_NUM IS NULL OR A.SVC_CT_NUM = '000000000' THEN 0 ELSE 1 END svcCtNum , FN_GET_RPRSPRDTCD(B.PRDT_ID) AS prdtCode , B.PRDT_COLR_CD AS prdtColrCd , B.MNFCT_ID AS mnfctId , A.IN_ORGN_ID AS orgnId , FN_GET_ORGNM(A.IN_ORGN_ID) AS orgnNm FROM LGS_OTCP_SRL_MST A , CMN_INTM_MDL B WHERE 1 = 1
AND TO_CHAR(SYSDATE, 'YYYYMMDD')
AND REPLACE(#{reqInDay}, '-', '')
BETWEEN NVL(B.PRDT_LNCH_DT,
TO_CHAR(SYSDATE, 'YYYYMMDD')
REPLACE(#{reqInDay}, '-', '')
) AND B.PRDT_DT
AND A.PRDT_SRL_NUM = #{reqPhoneSn}
AND A.RPRS_PRDT_ID = #{prdtId}
AND A.IN_ORGN_ID = #{cntpntShopId}
AND A.LOGIS_PROC_STAT_CD IN ( SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'LGS1000' AND ETC3 = 'AG' AND ETC5 = 'Z11' ) AND A.PRDT_ID = B.PRDT_ID

/* RcpNewMgmtMapper.getPrdtStatList */ SELECT A.ORGN_ID AS orgnId , FN_GET_ORGNM(A.ORGN_ID) AS orgnNm , A.RPRS_PRDT_ID AS prdtId , FN_GET_RPRSPRDTCD(A.PRDT_ID) AS prdtCode , B.PRDT_NM AS prdtNm , B.PRDT_COLR_CD AS prdtColrCd , FN_GET_CODENM('CMN0044', B.PRDT_COLR_CD) AS prdtColrNm , A.PRDT_SRL_NUM AS prdtSrlNum , A.LOGIS_PROC_STAT_CD AS logisProcStatCd , FN_GET_CODENM('LGS1000', A.LOGIS_PROC_STAT_CD) AS logisProcStatNm , B.MNFCT_ID AS mnfctId FROM LGS_PRDT_SRL_MST A , CMN_INTM_MDL B WHERE 1=1 AND A.PRDT_ID = B.PRDT_ID AND B.PRDT_TYPE_CD = '01'
AND TO_CHAR(SYSDATE, 'YYYYMMDD')
AND REPLACE(#{reqInDay}, '-', '')
BETWEEN NVL(B.PRDT_LNCH_DT,
TO_CHAR(SYSDATE, 'YYYYMMDD')
REPLACE(#{reqInDay}, '-', '')
) AND B.PRDT_DT
AND A.PRDT_SRL_NUM = #{prdtSrlNum}
AND B.RPRS_PRDT_ID = #{prdtId}
AND A.ORGN_ID = #{orgnId}

SELECT A.ORGN_ID AS orgnId ,A.STRT_YM AS strtYm ,A.END_YM AS endYm ,A.PRDT_ID AS prdtId ,B.PRDT_NM AS prdtNm ,B.PRDT_CODE AS prdtCode ,A.BUY_AMNT AS buyAmnt ,A.RENTAL_COST AS rentalCost FROM MSP_RNTL_BASE_INFO A ,CMN_INTM_MDL B WHERE A.PRDT_ID = B.PRDT_ID AND B.RPRS_YN = 'Y' AND #{baseYm} BETWEEN A.STRT_YM AND A.END_YM
AND A.ORGN_ID = #{orgnId}
ORDER BY B.PRDT_NM

SELECT /* RcpNewMgmtMapper.getRcpPrmtPrdcList */ DISTINCT B.RATE_CD AS rateCd , C.RATE_NM AS rateNm FROM MSP_PROMOTION_MST A , MSP_PRMT_RATE B , MSP_RATE_MST C WHERE #{reqInDay} BETWEEN A.STRT_DT AND A.END_DT AND A.CNFM_YN = 'Y' AND A.PROMOTION_CD = B.PROMOTION_CD AND B.RATE_CD = C.RATE_CD AND #{reqInDay} BETWEEN C.APPL_STRT_DT AND C.APPL_END_DT
AND B.RATE_CD = #{rateCd}
ORDER BY C.RATE_NM

SELECT DISTINCT CONTRACT_NUM 
  FROM MSP_JUO_SUB_INFO_HIST 
 WHERE SVC_CNTR_NO = #{pSearchName}

mapper.delete:
/* RcpNewMgmtMapper.deleteRcpBenefit */
DELETE FROM MCP_REQUEST_BENEFIT@DL_MCP
WHERE REQUEST_KEY = #{requestKey}

mapper.insert:
/* RcpNewMgmtMapper.insertCopyRcpBenefit */
INSERT INTO MCP_REQUEST_BENEFIT@DL_MCP
	(REQUEST_KEY
	,CD
	,CD_NM
	)
SELECT
	#{requestKey}
	,CD
	,CD_NM
FROM MCP_REQUEST_BENEFIT@DL_MCP
WHERE REQUEST_KEY = #{trgtRequestKey}

mapper.select:
/* rcpNewMgmtMapper.getAppFormMakeCheck */
SELECT  COUNT(1)
FROM    CMN_GRP_CD_MST
WHERE   GRP_ID = 'RCP3001'
AND     USG_YN = 'Y'
AND     CD_VAL = #{cntpntShopId}

/* rcpNewMgmtMapper.getRcpNatnList */ SELECT A.CD_VAL AS natnCd ,A.CD_DSC AS natnNm FROM CMN_GRP_CD_MST A WHERE A.GRP_ID = 'RCP2038' AND A.USG_YN = 'Y'
AND UPPER(A.CD_DSC) LIKE UPPER('%'|| #{searchNm} ||'%')
ORDER BY A.CD_DSC

mapper.update:
/* rcpNewMgmtMapper.updateRequestState */
UPDATE   MCP_REQUEST@DL_MCP A
SET      PSTATE = '30'
WHERE    REQUEST_KEY = #{trgtRequestKey}

mapper.select:
/* RcpNewMgmtMapper.chkCstmrCnt */ SELECT COUNT(A.CONTRACT_NUM) FROM MSP_JUO_SUB_INFO A,MSP_JUO_CUS_INFO B WHERE A.CUSTOMER_ID = B.CUSTOMER_ID AND TO_DATE(A.LST_COM_ACTV_DATE ,'YYYYMMDD') > SYSDATE - 90 AND A.PPPO = 'PO' AND A.SUB_STATUS = 'C' AND A.SUB_STATUS_RSN_CODE IN ('PN6','PN7') AND B.CUSTOMER_TYPE = 'I'
AND B.CUSTOMER_SSN = CRYPTO_AES256.ENC_AES(#{cstmrNativeRrn})
AND B.CUSTOMER_SSN = CRYPTO_AES256.ENC_AES(#{cstmrForeignerRrn})

/* rcpNewMgmtMapper.getCommendId */
SELECT COUNT(1) 
   FROM MCP_COMMEND_ID_MNG@DL_MCP
WHERE 
 COMMEND_ID  = (SELECT DISTINCT RECOMMEND_INFO 
 								FROM MCP_REQUEST_CSTMR@DL_MCP 
 							 WHERE REQUEST_KEY = #{trgtRequestKey} 
 							 	AND RECOMMEND_INFO IS NOT NULL
 							 	AND RECOMMEND_FLAG_CD  = #{recommendFlagCd}
 						)

mapper.insert:
        INSERT INTO MCP_REQUEST_COMMEND@DL_MCP (
             REQUEST_KEY
		    ,RES_NO
		    ,COMMEND_ID
		    ,APPLY_YN
		    ,SYS_RDATE
		    ,RVISN_DTTM
		    ,LINK_TYPE_CD

		    ,OPEN_MTHD_CD
			,COMMEND_SOC_CODE_01
			,COMMEND_SOC_CODE_02
			,COMMEND_SOC_CODE_03

        )VALUES(
		     #{requestKey}
		   , #{resNo}
		    , (SELECT DISTINCT RECOMMEND_INFO  FROM MCP_REQUEST_CSTMR@DL_MCP WHERE REQUEST_KEY = #{trgtRequestKey} AND RECOMMEND_FLAG_CD  = #{recommendFlagCd} AND RECOMMEND_INFO IS NOT NULL)
			, 'N'
			, SYSDATE
			, SYSDATE
			, #{linkTypeCd}

			, #{openMthdCd}
			, #{commendSocCode01}
			, #{commendSocCode02}
			, #{commendSocCode03}

			)

mapper.select:
  /*rcpNewMgmtMapper.getAcenReqStatus*/
	SELECT END_STATUS
	FROM NMCP_ACEN_REQ@DL_MCP
	WHERE REQUEST_KEY = #{requestKey}

/*rcpNewMgmtMapper.getMovePenalty*/
SELECT MOVE_PENALTY
FROM MCP_REQUEST_MOVE@DL_MCP
