mapper.insert:
/*rcpNewMgmtMapper.insertPenaltyHist*/
INSERT INTO MSP_REQUEST_PENALTY_HIST(
	 REQUEST_KEY
	,SEQ
	,MOVE_PENALTY
	,REGST_ID
	,REGST_DTTM
) VALUES(
	 #{requestKey}
	,NVL((SELECT MAX(SEQ) + 1 FROM MSP_REQUEST_PENALTY_HIST WHERE REQUEST_KEY= #{requestKey}), 1)
	,#{movePenalty}
	,#{sessionUserId}
	,SYSDATE
)

