mapper.select:
/* RcpNewMgmtMapper.getRcpRequestList */
SELECT /*+ INDEX(REQ MCP_REQUEST_IDX4 PK_MCP_REQUEST MCP_REQUEST_IDX3 MCP_REQUEST_IDX9) USE_NL(REQ DTL) */ REQ.REQUEST_KEY, FN_GET_CODENM('RCP0063',REQ.PROD_TYPE) AS PROD_TYPE_NM, /*상품구분*/ REQ.RES_NO, /*예약번호*/ FN_GET_CODENM('CMN0058',DTL.SPRT_TP) AS SPRT_TP_NM, /*할인유형*/ DTL.CSTMR_NAME, /*고객명*/ DTL.BIRTH_DT AS BIRTH_DAY, /*생년월일*/ CASE WHEN REQ.CSTMR_TYPE = 'JP' THEN '법인' ELSE DTL.CSTMR_GENDER_STR END AS CSTMR_GENDER_STR, /*성별*/ REQ.CSTMR_TYPE, CASE WHEN LENGTH(DTL.CSTMR_MOBILE) = '11' THEN SUBSTR(DTL.CSTMR_MOBILE, 1, 3) || '-' || SUBSTR(DTL.CSTMR_MOBILE, 4, 4) || '-' || SUBSTR(DTL.CSTMR_MOBILE, 8, 4) /*연락처*/ ELSE SUBSTR(DTL.CSTMR_MOBILE, 1, 3) || '-' || SUBSTR(DTL.CSTMR_MOBILE, 4, 3) || '-' || SUBSTR(DTL.CSTMR_MOBILE, 7, 4) /*연락처*/ END AS CSTMR_MOBILE, FN_GET_ORGNM(REQ.CNTPNT_SHOP_ID) || '/' || REQ.CNTPNT_SHOP_ID AS AGENT_NAME, /*대리점*/ ( SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = DTL.SOC_CODE AND SERVICE_TYPE = 'P' AND ROWNUM = 1 ) || '(' || DTL.SOC_CODE || ')' AS SOC_NAME, /*요금제*/ DECODE(SUBSTR(REQ.DIS_PRMT_ID,1,1),'F',(SELECT '(오프라인) ' || PRMT_NM FROM MSP_DIS_MST WHERE PRMT_ID = REQ.DIS_PRMT_ID), 'C',(SELECT '(온라인) ' || PRMT_NM FROM MSP_CHRG_PRMT WHERE PRMT_ID = REQ.DIS_PRMT_ID),'','') AS DIS_PRMT_NM, /*평생할인프로모션명*/ FN_GET_CODENM('RCP9001',REQ.OPER_TYPE) AS OPER_NAME, /*업무구분*/ TO_CHAR(REQ.REQ_IN_DAY, 'YYYY-MM-DD') AS REQ_IN_DAY, /*신청일자*/ FN_GET_CODENM('RCP0006',REQ.REQUEST_STATE_CODE) AS REQUEST_STATE_NAME, /*진행상태*/ FN_GET_CODENM('RCP0005',REQ.PSTATE) AS PSTATE_NAME, /*신청서상태*/ FN_GET_CODENM('RCP0007',REQ.ON_OFF_TYPE) AS ON_OFF_NAME, /*모집경로*/ REQ.OPEN_MARKET_REFERER, /*유입경로*/ FN_GET_CODENM('RCP9011',DTL.RECOMMEND_FLAG_CD) AS RECOMMEND_FLAG_NM, /*추천인구분*/ DTL.RECOMMEND_INFO, /*추천인정보*/ REQ.REC_YN, /*녹취여부*/ FN_GET_ORGNM(REQ.SHOP_CD) || '/' || REQ.SHOP_CD AS SHOP_NM, /*판매점명*/ FN_GET_USRNM(REQ.SHOP_USM_ID) AS USR_NM, /*판매자*/ REQ.SHOP_USM_ID AS USR_ID, /*판매자ID*/ DECODE(REQ.RVISN_ID, 'ACEN', REQ.RVISN_ID, FN_GET_USRNM(REQ.RVISN_ID)) AS RVISN_NM, /*수정자*/ TO_CHAR(REQ.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM, /*수정일자*/ '후불' AS SERVICE_NAME, ( SELECT COUNT(1) FROM CMN_GRP_CD_MST A WHERE A.GRP_ID = 'RCP0073' AND A.USG_YN = 'Y' AND A.CD_VAL = REQ.CNTPNT_SHOP_ID AND EXISTS (SELECT 1 FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP0074' AND CD_VAL = REQ.OPER_TYPE AND USG_YN = 'Y') AND EXISTS (SELECT 1 FROM CMN_USR_MST WHERE USR_ID = #{sessionUserId} AND KOS_ID IS NOT NULL) ) AS OSST_CHK, REQ.SCAN_ID FROM MCP_REQUEST@DL_MCP REQ, MCP_REQUEST_DTL@DL_MCP DTL WHERE 1 = 1 AND REQ.REQUEST_KEY = DTL.REQUEST_KEY
AND REQ.REQ_IN_DAY BETWEEN TO_DATE(#{searchStartDt},'YYYYMMDD') AND TO_DATE(#{searchEndDt},'YYYYMMDD') + 1 /*신청일자*/
AND 1=1 /*서비스타입-후불*/
AND 1=2 /*서비스타입-선불*/
AND REQ.OPER_TYPE = #{pOperType} /*신청유형-신규가입/번호이동정보/기기변경정보*/
AND REQ.CNTPNT_SHOP_ID = #{cntpntShopId}
AND REQ.SHOP_CD = #{pAgentCode}
AND (REQ.SHOP_CD = #{pAgentCode} OR REQ.CNTPNT_SHOP_ID = #{pAgentCode})
AND REQ.SHOP_CD = #{pAgentCode}
AND REQ.REQUEST_STATE_CODE = #{pRequestStateCode} /*접수상태코드-진행상태*/
AND DTL.CSTMR_NAME LIKE #{pSearchName} || '%' /*검색구분-고객명(pSearchGbn=1로 구분)*/
AND CONTRACT_NUM = #{pSearchName} /*검색구분-예약번호(pSearchGbn=2로 구분)*/
AND DTL.CSTMR_MOBILE = #{pSearchName} /*검색구분-연락처(searchGbn=3로 구분)*/
AND REQ.REQ_PHONE_SN = #{pSearchName}
AND REQ.RES_NO = #{pSearchName}
AND DTL.SOC_CODE IN ( SELECT RATE_CD FROM MSP_RATE_MST WHERE SERVICE_TYPE = 'P' AND RATE_NM LIKE UPPER(#{pSearchName}) || '%' )
AND REQ.PSTATE = #{pPstate}
AND REQ.REQ_BUY_TYPE = #{reqBuyType}
AND DTL.SPRT_TP = #{sprtTp}
AND NVL(REQ.PROD_TYPE, '01') = #{prodType}
AND REQ.ON_OFF_TYPE = #{onOffType}
AND REQ.USIM_KINDS_CD = '09'
--AND EXISTS (SELECT 1 FROM NMCP_ACEN_REQ@DL_MCP WHERE REQUEST_KEY = REQ.REQUEST_KEY) AND REQ.REQUEST_KEY IN (SELECT REQUEST_KEY FROM NMCP_ACEN_REQ@DL_MCP ACEN WHERE ACEN.REQUEST_KEY = REQ.REQUEST_KEY)
AND REQ.ON_OFF_TYPE NOT IN ('5','7')
AND BIRTH_DT = #{pBirthDayVal}
ORDER BY REQ.REQUEST_KEY DESC
